import axios from 'axios'
import toast from 'react-hot-toast'

const API_BASE_URL = import.meta.env.VITE_API_URL || 'http://localhost:5000/api'

// Create axios instance
const api = axios.create({
  baseURL: API_BASE_URL,
  timeout: 15000,
  headers: {
    'Content-Type': 'application/json',
  },
})

// Request interceptor to add auth token
api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('token')
    if (token) {
      config.headers.Authorization = `Bearer ${token}`
    }
    return config
  },
  (error) => {
    return Promise.reject(error)
  }
)

// Response interceptor to handle errors
api.interceptors.response.use(
  (response) => response,
  (error) => {
    // Only logout on actual 401 authentication errors, not network errors
    if (error.response?.status === 401 && error.response?.data) {
      // This is a real auth error from the server
      localStorage.removeItem('token')
      localStorage.removeItem('user')
      // Dispatch logout action instead of redirecting
      window.dispatchEvent(new CustomEvent('auth-expired'))
    }
    // Don't reject network errors with 401 - let components handle API failures gracefully
    return Promise.reject(error)
  }
)

// Auth API
export const authAPI = {
  login: (credentials) => api.post('/auth/login', credentials),
  register: (userData) => api.post('/auth/register', userData),
  getCurrentUser: () => api.get('/auth/me'),
  requestOtp: (data) => api.post('/auth/request-otp', data),
  sendVerificationOtp: (data) => api.post('/auth/send-verification-otp', data),
  verifyOtp: (data) => api.post('/auth/verify-otp', data),
  resetPassword: (data) => api.post('/auth/reset-password', data),
  changePassword: (data) => api.put('/auth/change-password', data),
  updateProfile: (data) => api.put('/auth/profile', data),
  getHybridPermissions: () => api.get('/hybrid-permissions/my-permission'),
}

// User API
export const userAPI = {
  getPendingAdmins: () => api.get('/users/pending-admins'),
  approveAdmin: (id) => api.patch(`/users/${id}/approve`),
  rejectAdmin: (id) => api.patch(`/users/${id}/reject`),
}

// Employee API
export const employeeAPI = {
  getAll: (params) => api.get('/employees', { params }),
  getById: (id) => api.get(`/employees/${id}`),
  create: (data) => api.post('/employees', data),
  update: (id, data) => api.put(`/employees/${id}`, data),
  delete: (id) => api.delete(`/employees/${id}`),
  toggleStatus: (id) => api.patch(`/employees/${id}/toggle-status`),
  getMe: () => api.get('/employees/me'),
  uploadDocument: (id, formData) => api.post(`/employees/${id}/documents`, formData, {
    headers: { 'Content-Type': 'multipart/form-data' }
  }),
  submitExpense: (formData) => api.post('/employees/expenses', formData, {
    headers: { 'Content-Type': 'multipart/form-data' }
  }),
  getPayslip: (id, month) => api.get(`/employees/${id}/payroll/${month}/payslip`, { responseType: 'blob' }),
}

// Attendance API
export const attendanceAPI = {
  checkIn: (data) => api.post('/attendance/check-in', data),
  checkOut: (data) => api.post('/attendance/check-out', data),
  getTodayAttendance: () => api.get('/attendance/today'),
  getMyTodayAttendance: () => api.get('/attendance/my-today'),
  getMyHistory: (params) => api.get('/attendance/my-history', { params }),
  getAttendanceHistory: (params) => api.get('/attendance/history', { params }),
  getMonthlyReport: (params) => api.get('/attendance/monthly-report', { params }),
  getAttendanceStats: (params) => api.get('/attendance/stats', { params }),
  mark: (data) => api.post('/attendance/mark', data),
  update: (id, data) => api.put(`/attendance/${id}`, data),
  remove: (id) => api.delete(`/attendance/${id}`),
}

// Location API
export const locationAPI = {
  getCurrentLocation: () => api.get('/location/current'),
  updateLocation: (data) => api.post('/location/update', data),
  getLocationHistory: (params) => api.get('/location/history', { params }),
  getLiveLocations: () => api.get('/location/live'),
  getRouteHistory: (params) => api.get('/location/route-history', { params }),
}

// Map API
export const mapAPI = {
  updateLiveLocation: (data) => api.post('/live-location/update', data),
  getMapLocations: () => api.get('/map/locations'),
  getLocationHistory: (userId) => api.get(`/map/location-history/${userId}`),
}

// Service API
export const serviceAPI = {
  getAll: (params) => api.get('/services', { params }),
  getById: (id) => api.get(`/services/${id}`),
  create: (data) => api.post('/services', data),
  update: (id, data) => api.put(`/services/${id}`, data),
  delete: (id) => api.delete(`/services/${id}`),
  assignService: (id, data) => api.post(`/services/${id}/assign`, data),
  updateStatus: (id, status) => api.patch(`/services/${id}/status`, { status }),
  getMyServices: () => api.get('/services/my'),
}

// Notification API
export const notificationAPI = {
  getAll: (params) => api.get('/notifications', { params }),
  create: (data) => api.post('/notifications', data),
  markAsRead: (id) => api.patch(`/notifications/${id}/read`),
  markAllAsRead: () => api.patch('/notifications/read-all'),
  getUnreadCount: (params) => api.get('/notifications/unread-count', { params }),
  delete: (id) => api.delete(`/notifications/${id}`),
}

// Reports API
export const reportsAPI = {
  exportAttendance: (params) => api.get('/reports/attendance', { params, responseType: 'blob' }),
  exportEmployees: () => api.get('/reports/employees', { responseType: 'blob' }),
  exportPayroll: (params) => api.get('/reports/payroll', { params, responseType: 'blob' }),
}

// Leave API
export const leaveAPI = {
  apply: (data) => api.post('/leaves', data),
  getMyLeaves: () => api.get('/leaves/my'),
  getAll: () => api.get('/leaves'),
  updateStatus: (id, data) => api.put(`/leaves/${id}/status`, data),
}

// Settings API
export const settingsAPI = {
  getUserSettings: () => api.get('/settings/user'),
  updateUserSettings: (data) => api.put('/settings/user', data),
  getSystemSettings: () => api.get('/settings/system'),
  updateSystemSettings: (data) => api.put('/settings/system', data),
}

// Expense API
export const expenseAPI = {
  getAll: () => api.get('/expenses/all'),
  getMyExpenses: () => api.get('/expenses/my'),
  submit: (data) => api.post('/expenses/submit', data),
  updateStatus: (id, data) => api.patch(`/expenses/status/${id}`, data),
}



// Payroll API
export const payrollAPI = {
  getAll: (params) => api.get('/payroll/all', { params }),
  getMyHistory: () => api.get('/payroll/my'),
  generate: (data) => api.post('/payroll/generate', data),
  updateStatus: (id, data) => api.patch(`/payroll/status/${id}`, data),
}

// Shift API
export const shiftAPI = {
  getAll: (params) => api.get('/shifts/all', { params }),
  getMyHistory: (params) => api.get('/shifts/my', { params }),
  assign: (data) => api.post('/shifts/assign', data),
  remove: (id) => api.delete(`/shifts/${id}`),
}

// Ticket API
export const ticketAPI = {
  getAll: (params) => api.get('/tickets/all', { params }),
  getMyTickets: () => api.get('/tickets/my'),
  create: (data) => api.post('/tickets/create', data),
  update: (id, data) => api.patch(`/tickets/${id}`, data),
}

// Hybrid Permission API
export const hybridPermissionAPI = {
  getAll: () => api.get('/hybrid-permissions/all'),
  grant: (data) => api.post('/hybrid-permissions/grant', data),
  revoke: (id) => api.patch(`/hybrid-permissions/revoke/${id}`),
  myPermission: () => api.get('/hybrid-permissions/my-permission'),
}

export default api

// Service request management system
class ServiceService {
  constructor() {
    this.services = []
    this.categories = [
      { id: 'it', name: 'IT Support', icon: '💻' },
      { id: 'hr', name: 'HR Services', icon: '👥' },
      { id: 'facilities', name: 'Facilities', icon: '🏢' },
      { id: 'maintenance', name: 'Maintenance', icon: '🔧' },
      { id: 'security', name: 'Security', icon: '🔒' },
      { id: 'admin', name: 'Administrative', icon: '📋' }
    ]
    this.priorities = [
      { id: 'low', name: 'Low', color: '#4caf50' },
      { id: 'normal', name: 'Normal', color: '#00c853' },
      { id: 'high', name: 'High', color: '#00c853' },
      { id: 'urgent', name: 'Urgent', color: '#00c853' }
    ]
    this.statuses = [
      { id: 'pending', name: 'Pending', color: '#9e9e9e' },
      { id: 'assigned', name: 'Assigned', color: '#00c853' },
      { id: 'in_progress', name: 'In Progress', color: '#00c853' },
      { id: 'resolved', name: 'Resolved', color: '#4caf50' },
      { id: 'closed', name: 'Closed', color: '#666666' },
      { id: 'cancelled', name: 'Cancelled', color: '#00c853' }
    ]
  }

  // Create new service request
  createServiceRequest(serviceData) {
    const serviceRequest = {
      id: 'SR' + Date.now(),
      title: serviceData.title,
      description: serviceData.description,
      category: serviceData.category,
      priority: serviceData.priority || 'normal',
      status: 'pending',
      requesterId: serviceData.requesterId,
      requesterName: serviceData.requesterName,
      requesterEmail: serviceData.requesterEmail,
      requesterDepartment: serviceData.requesterDepartment,
      assignedToId: null,
      assignedToName: null,
      assignedToEmail: null,
      location: serviceData.location || null,
      estimatedTime: serviceData.estimatedTime || null,
      actualTime: null,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      dueDate: serviceData.dueDate || null,
      completedAt: null,
      attachments: serviceData.attachments || [],
      tags: serviceData.tags || [],
      comments: [],
      history: [
        {
          action: 'created',
          timestamp: new Date().toISOString(),
          userId: serviceData.requesterId,
          userName: serviceData.requesterName,
          details: 'Service request created'
        }
      ],
      rating: null,
      feedback: null,
      metadata: serviceData.metadata || {}
    }

    this.services.push(serviceRequest)
    return serviceRequest
  }

  // Update service request
  updateServiceRequest(serviceId, updates, userId, userName) {
    const service = this.services.find(s => s.id === serviceId)
    if (!service) {
      throw new Error('Service request not found')
    }

    const previousStatus = service.status
    Object.assign(service, updates)
    service.updatedAt = new Date().toISOString()

    // Add to history
    service.history.push({
      action: 'updated',
      timestamp: new Date().toISOString(),
      userId: userId,
      userName: userName,
      details: `Updated: ${Object.keys(updates).join(', ')}`,
      changes: updates
    })

    // Handle status change
    if (updates.status && updates.status !== previousStatus) {
      this.handleStatusChange(service, previousStatus, updates.status, userId, userName)
    }

    return service
  }

  // Handle status changes
  handleStatusChange(service, oldStatus, newStatus, userId, userName) {
    const statusChange = {
      action: 'status_changed',
      timestamp: new Date().toISOString(),
      userId: userId,
      userName: userName,
      details: `Status changed from ${oldStatus} to ${newStatus}`,
      oldStatus: oldStatus,
      newStatus: newStatus
    }

    service.history.push(statusChange)

    // Set completion timestamp
    if (newStatus === 'resolved' || newStatus === 'closed') {
      service.completedAt = new Date().toISOString()
    }

    // Calculate actual time if service is completed
    if (newStatus === 'resolved' && service.createdAt) {
      const created = new Date(service.createdAt)
      const completed = new Date(service.completedAt)
      service.actualTime = Math.round((completed - created) / (1000 * 60 * 60)) // hours
    }
  }

  // Assign service request to employee
  assignServiceRequest(serviceId, assigneeId, assigneeName, assigneeEmail, userId, userName) {
    return this.updateServiceRequest(serviceId, {
      assignedToId: assigneeId,
      assignedToName: assigneeName,
      assignedToEmail: assigneeEmail,
      status: 'assigned'
    }, userId, userName)
  }

  // Add comment to service request
  addComment(serviceId, comment, userId, userName, isInternal = false) {
    const service = this.services.find(s => s.id === serviceId)
    if (!service) {
      throw new Error('Service request not found')
    }

    const commentData = {
      id: Date.now().toString(),
      text: comment,
      userId: userId,
      userName: userName,
      timestamp: new Date().toISOString(),
      isInternal: isInternal
    }

    service.comments.push(commentData)
    service.updatedAt = new Date().toISOString()

    // Add to history
    service.history.push({
      action: 'comment_added',
      timestamp: new Date().toISOString(),
      userId: userId,
      userName: userName,
      details: `Comment added: ${comment.substring(0, 50)}...`
    })

    return commentData
  }

  // Add attachment to service request
  addAttachment(serviceId, attachment, userId, userName) {
    const service = this.services.find(s => s.id === serviceId)
    if (!service) {
      throw new Error('Service request not found')
    }

    const attachmentData = {
      id: Date.now().toString(),
      name: attachment.name,
      size: attachment.size,
      type: attachment.type,
      url: attachment.url,
      uploadedBy: userId,
      uploadedByName: userName,
      uploadedAt: new Date().toISOString()
    }

    service.attachments.push(attachmentData)
    service.updatedAt = new Date().toISOString()

    return attachmentData
  }

  // Rate and provide feedback for completed service
  rateService(serviceId, rating, feedback, userId, userName) {
    return this.updateServiceRequest(serviceId, {
      rating: rating,
      feedback: feedback
    }, userId, userName)
  }

  // Get service request by ID
  getServiceRequest(serviceId) {
    return this.services.find(s => s.id === serviceId) || null
  }

  // Get all service requests with filters
  getServiceRequests(filters = {}) {
    let services = [...this.services]

    // Apply filters
    if (filters.status) {
      services = services.filter(s => s.status === filters.status)
    }
    if (filters.priority) {
      services = services.filter(s => s.priority === filters.priority)
    }
    if (filters.category) {
      services = services.filter(s => s.category === filters.category)
    }
    if (filters.requesterId) {
      services = services.filter(s => s.requesterId === filters.requesterId)
    }
    if (filters.assignedToId) {
      services = services.filter(s => s.assignedToId === filters.assignedToId)
    }
    if (filters.dateRange) {
      const { start, end } = filters.dateRange
      services = services.filter(s => {
        const created = new Date(s.createdAt)
        return created >= start && created <= end
      })
    }
    if (filters.search) {
      const searchTerm = filters.search.toLowerCase()
      services = services.filter(s => 
        s.title.toLowerCase().includes(searchTerm) ||
        s.description.toLowerCase().includes(searchTerm)
      )
    }

    // Sort
    if (filters.sortBy) {
      services.sort((a, b) => {
        switch (filters.sortBy) {
          case 'createdAt':
            return new Date(b.createdAt) - new Date(a.createdAt)
          case 'priority':
            const priorityOrder = { urgent: 4, high: 3, normal: 2, low: 1 }
            return priorityOrder[b.priority] - priorityOrder[a.priority]
          case 'status':
            return a.status.localeCompare(b.status)
          default:
            return 0
        }
      })
    }

    return services
  }

  // Get service statistics
  getStatistics(filters = {}) {
    const services = this.getServiceRequests(filters)
    
    const stats = {
      total: services.length,
      byStatus: {},
      byPriority: {},
      byCategory: {},
      averageResolutionTime: 0,
      completionRate: 0,
      satisfactionScore: 0
    }

    let totalResolutionTime = 0
    let completedServices = 0
    let totalRating = 0
    let ratedServices = 0

    services.forEach(service => {
      // Status statistics
      stats.byStatus[service.status] = (stats.byStatus[service.status] || 0) + 1
      
      // Priority statistics
      stats.byPriority[service.priority] = (stats.byPriority[service.priority] || 0) + 1
      
      // Category statistics
      stats.byCategory[service.category] = (stats.byCategory[service.category] || 0) + 1
      
      // Resolution time
      if (service.actualTime) {
        totalResolutionTime += service.actualTime
        completedServices++
      }
      
      // Satisfaction score
      if (service.rating) {
        totalRating += service.rating
        ratedServices++
      }
    })

    stats.averageResolutionTime = completedServices > 0 ? 
      Math.round(totalResolutionTime / completedServices) : 0
    
    stats.completionRate = services.length > 0 ? 
      Math.round((completedServices / services.length) * 100) : 0
    
    stats.satisfactionScore = ratedServices > 0 ? 
      Math.round((totalRating / ratedServices) * 10) / 10 : 0

    return stats
  }

  // Get services assigned to user
  getAssignedServices(userId) {
    return this.services.filter(s => s.assignedToId === userId)
  }

  // Get services requested by user
  getRequestedServices(userId) {
    return this.services.filter(s => s.requesterId === userId)
  }

  // Get overdue services
  getOverdueServices() {
    const now = new Date()
    return this.services.filter(s => 
      s.dueDate && 
      new Date(s.dueDate) < now && 
      !['resolved', 'closed', 'cancelled'].includes(s.status)
    )
  }

  // Get services needing attention
  getServicesNeedingAttention() {
    return this.services.filter(s => 
      ['pending', 'assigned'].includes(s.status) && s.priority === 'urgent'
    )
  }

  // Export service data
  exportServiceData(format = 'json', filters = {}) {
    const services = this.getServiceRequests(filters)
    
    if (format === 'json') {
      return JSON.stringify(services, null, 2)
    } else if (format === 'csv') {
      const headers = [
        'ID', 'Title', 'Category', 'Priority', 'Status', 
        'Requester', 'Assigned To', 'Created Date', 'Due Date', 'Completed Date'
      ]
      
      const rows = services.map(s => [
        s.id,
        s.title,
        s.category,
        s.priority,
        s.status,
        s.requesterName,
        s.assignedToName || 'Unassigned',
        s.createdAt,
        s.dueDate || '',
        s.completedAt || ''
      ])
      
      return [headers, ...rows].map(row => row.join(',')).join('\n')
    }
    
    return services
  }

  // Get categories
  getCategories() {
    return this.categories
  }

  // Get priorities
  getPriorities() {
    return this.priorities
  }

  // Get statuses
  getStatuses() {
    return this.statuses
  }

  // Delete service request
  deleteServiceRequest(serviceId, userId, userName) {
    const index = this.services.findIndex(s => s.id === serviceId)
    if (index === -1) {
      throw new Error('Service request not found')
    }

    const service = this.services[index]
    
    // Add to history before deletion
    service.history.push({
      action: 'deleted',
      timestamp: new Date().toISOString(),
      userId: userId,
      userName: userName,
      details: 'Service request deleted'
    })

    // Archive instead of actual delete
    this.services.splice(index, 1)
    return service
  }

  // Bulk operations
  bulkUpdate(serviceIds, updates, userId, userName) {
    const results = []
    
    serviceIds.forEach(serviceId => {
      try {
        const updated = this.updateServiceRequest(serviceId, updates, userId, userName)
        results.push({ success: true, serviceId, service: updated })
      } catch (error) {
        results.push({ success: false, serviceId, error: error.message })
      }
    })
    
    return results
  }
}

// Create singleton instance
const serviceService = new ServiceService()

export default serviceService
